import sys
input = sys.stdin.readline

def min_c3_needed(a, c1, c2):
    max_rem = c1 + 2 * c2
    # We want minimum x3 such that r = a - 3*x3 is in [0, max_rem] and reachable
    # r = a - 3*x3 >= 0 => x3 <= a//3
    # r <= max_rem => x3 >= (a - max_rem) / 3
    min_x3 = max(0, (a - max_rem + 2) // 3)  # ceil((a-max_rem)/3)
    # Try x3 = min_x3, min_x3+1, min_x3+2 (at most 3 to fix parity)
    for x3 in range(min_x3, min_x3 + 3):
        r = a - 3 * x3
        if r < 0:
            return float('inf')
        if r <= max_rem:
            if c1 >= 1 or r % 2 == 0:
                return x3
    return float('inf')

T = int(input())
for _ in range(T):
    n = int(input())
    a = list(map(int, input().split()))

    best = float('inf')
    for c1 in range(3):
        for c2 in range(3):
            c3 = 0
            for ai in a:
                needed = min_c3_needed(ai, c1, c2)
                c3 = max(c3, needed)
            total = c1 + c2 + c3
            best = min(best, total)

    print(best)
